    public function fetch_funding_history(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()) {
        /**
         * fetch the history of funding payments paid and received on this account
         *
         * @see https://asterdex.github.io/aster-api-website/futures-v3/account%26trades/#get-income-historyuser_data
         *
         * @param {string} $symbol unified $market $symbol
         * @param {int} [$since] the earliest time in ms to fetch funding history for
         * @param {int} [$limit] the maximum number of funding history structures to retrieve
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {int} [$params->until] timestamp in ms of the latest funding history entry
         * @param {boolean} [$params->portfolioMargin] set to true if you would like to fetch the funding history for a portfolio margin account
         * @param {string} [$params->subType] "linear" or "inverse"
         * @return {array} a ~@link https://docs.ccxt.com/#/?id=funding-history-structure funding history structure~
         */
        $this->load_markets_and_sign_in();
        $market = null;
        $request = array(
            'incomeType' => 'FUNDING_FEE', // "TRANSFER"，"WELCOME_BONUS", "REALIZED_PNL"，"FUNDING_FEE", "COMMISSION", "INSURANCE_CLEAR", and "MARKET_MERCHANT_RETURN_REWARD"
        );
        if ($symbol !== null) {
            $market = $this->market($symbol);
            $request['symbol'] = $market['id'];
        }
        list($request, $params) = $this->handle_until_option('endTime', $request, $params);
        if ($since !== null) {
            $request['startTime'] = $since;
        }
        if ($limit !== null) {
            $request['limit'] = min ($limit, 1000); // max 1000
        }
        $response = $this->fapiPrivateGetV3Income ($this->extend($request, $params));
        return $this->parse_incomes($response, $market, $since, $limit);
    }

    public function parse_ledger_entry(array $item, ?array $currency = null): array {
        //
        //     {
        //         "symbol" => "",
        //         "incomeType" => "TRANSFER",
        //         "income" => "10.00000000",
        //         "asset" => "USDT",
        //         "time" => 1677645250000,
        //         "info" => "TRANSFER",
        //         "tranId" => 131001573082,
        //         "tradeId" => ""
        //     }
        //
        $amount = $this->safe_string($item, 'income');
        $direction = null;
        if (Precise::string_le($amount, '0')) {
            $direction = 'out';
            $amount = Precise::string_mul('-1', $amount);
        } else {
            $direction = 'in';
        }
        $currencyId = $this->safe_string($item, 'asset');
        $code = $this->safe_currency_code($currencyId, $currency);
        $currency = $this->safe_currency($currencyId, $currency);
        $timestamp = $this->safe_integer($item, 'time');
        $type = $this->safe_string($item, 'incomeType');
        return $this->safe_ledger_entry(array(
            'info' => $item,
            'id' => $this->safe_string($item, 'tranId'),
            'direction' => $direction,
            'account' => null,
            'referenceAccount' => null,
            'referenceId' => $this->safe_string($item, 'tradeId'),
            'type' => $this->parse_ledger_entry_type($type),
            'currency' => $code,
            'amount' => $this->parse_number($amount),
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'before' => null,
            'after' => null,
            'status' => null,
            'fee' => null,
        ), $currency);
    }

    public function parse_ledger_entry_type($type) {
        $ledgerType = array(
            'TRANSFER' => 'transfer',
            'WELCOME_BONUS' => 'cashback',
            'REALIZED_PNL' => 'trade',
            'FUNDING_FEE' => 'fee',
            'COMMISSION' => 'commission',
            'INSURANCE_CLEAR' => 'settlement',
            'MARKET_MERCHANT_RETURN_REWARD' => 'cashback',
        );
        return $this->safe_string($ledgerType, $type, $type);
    }

    public function fetch_ledger(?string $code = null, ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         * fetch the history of changes, actions done by the user or operations that altered the balance of the user
         *
         * @see https://asterdex.github.io/aster-api-website/futures-v3/account%26trades/#get-income-historyuser_data
         *
         * @param {string} [$code] unified $currency $code
         * @param {int} [$since] timestamp in ms of the earliest ledger entry
         * @param {int} [$limit] max number of ledger entries to return
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {int} [$params->until] timestamp in ms of the latest ledger entry
         * @return {array} a ~@link https://docs.ccxt.com/#/?id=ledger ledger structure~
         */
        $this->load_markets_and_sign_in();
        $currency = null;
        if ($code !== null) {
            $currency = $this->currency($code);
        }
        $request = array();
        if ($since !== null) {
            $request['startTime'] = $since;
        }
        if ($limit !== null) {
            $request['limit'] = min ($limit, 1000); // max 1000
        }
        $until = $this->safe_integer($params, 'until');
        if ($until !== null) {
            $params = $this->omit($params, 'until');
            $request['endTime'] = $until;
        }
        $response = $this->fapiPrivateGetV3Income ($this->extend($request, $params));
        //
        //     array(
        //         {
        //             "symbol" => "",
        //             "incomeType" => "TRANSFER",
        //             "income" => "10.00000000",
        //             "asset" => "USDT",
        //             "time" => 1677645250000,
        //             "info" => "TRANSFER",
        //             "tranId" => 131001573082,
        //             "tradeId" => ""
        //         }
        //     )
        //
        return $this->parse_ledger($response, $currency, $since, $limit);
    }

    public function parse_position_risk($position, ?array $market = null) {
        //
        //     {
        //         "entryPrice" => "6563.66500",
        //         "marginType" => "isolated",
        //         "isAutoAddMargin" => "false",
        //         "isolatedMargin" => "15517.54150468",
        //         "leverage" => "10",
        //         "liquidationPrice" => "5930.78",
        //         "markPrice" => "6679.50671178",
        //         "maxNotionalValue" => "20000000",
        //         "positionSide" => "LONG",
        //         "positionAmt" => "20.000",
        //         "symbol" => "BTCUSDT",
        //         "unRealizedProfit" => "2316.83423560",
        //         "updateTime" => 1625474304765
        //     }
        //
        $marketId = $this->safe_string($position, 'symbol');
        $market = $this->safe_market($marketId, $market, null, 'contract');
        $symbol = $this->safe_string($market, 'symbol');
        $isolatedMarginString = $this->safe_string($position, 'isolatedMargin');
        $leverageBrackets = $this->safe_dict($this->options, 'leverageBrackets', array());
        $leverageBracket = $this->safe_list($leverageBrackets, $symbol, array());
        $notionalString = $this->safe_string_2($position, 'notional', 'notionalValue');
        $notionalStringAbs = Precise::string_abs($notionalString);
        $maintenanceMarginPercentageString = null;
        for ($i = 0; $i < count($leverageBracket); $i++) {
            $bracket = $leverageBracket[$i];
            if (Precise::string_lt($notionalStringAbs, $bracket[0])) {
                break;
            }
            $maintenanceMarginPercentageString = $bracket[1];
        }
        $notional = $this->parse_number($notionalStringAbs);
        $contractsAbs = Precise::string_abs($this->safe_string($position, 'positionAmt'));
        $contracts = $this->parse_number($contractsAbs);
        $unrealizedPnlString = $this->safe_string($position, 'unRealizedProfit');
        $unrealizedPnl = $this->parse_number($unrealizedPnlString);
        $liquidationPriceString = $this->omit_zero($this->safe_string($position, 'liquidationPrice'));
        $liquidationPrice = $this->parse_number($liquidationPriceString);
        $collateralString = null;
        $marginMode = $this->safe_string($position, 'marginType');
        if ($marginMode === null && $isolatedMarginString !== null) {
            $marginMode = Precise::string_eq($isolatedMarginString, '0') ? 'cross' : 'isolated';
        }
        $side = null;
        if (Precise::string_gt($notionalString, '0')) {
            $side = 'long';
        } elseif (Precise::string_lt($notionalString, '0')) {
            $side = 'short';
        }
        $entryPriceString = $this->safe_string($position, 'entryPrice');
        $entryPrice = $this->parse_number($entryPriceString);
        $contractSize = $this->safe_value($market, 'contractSize');
        $contractSizeString = $this->number_to_string($contractSize);
        // to notionalValue
        $linear = (is_array($position) && array_key_exists('notional', $position));
        if ($marginMode === 'cross') {
            // calculate $collateral
            $precision = $this->safe_dict($market, 'precision', array());
            $basePrecisionValue = $this->safe_string($precision, 'base');
            $quotePrecisionValue = $this->safe_string_2($precision, 'quote', 'price');
            $precisionIsUndefined = ($basePrecisionValue === null) && ($quotePrecisionValue === null);
            if (!$precisionIsUndefined) {
                if ($linear) {
                    // walletBalance = ($liquidationPrice * (±1 . mmp) ± $entryPrice) * $contracts
                    $onePlusMaintenanceMarginPercentageString = null;
                    $entryPriceSignString = $entryPriceString;
                    if ($side === 'short') {
                        $onePlusMaintenanceMarginPercentageString = Precise::string_add('1', $maintenanceMarginPercentageString);
                        $entryPriceSignString = Precise::string_mul('-1', $entryPriceSignString);
                    } else {
                        $onePlusMaintenanceMarginPercentageString = Precise::string_add('-1', $maintenanceMarginPercentageString);
                    }
                    $inner = Precise::string_mul($liquidationPriceString, $onePlusMaintenanceMarginPercentageString);
                    $leftSide = Precise::string_add($inner, $entryPriceSignString);
                    $quotePrecision = $this->precision_from_string($this->safe_string_2($precision, 'quote', 'price'));
                    if ($quotePrecision !== null) {
                        $collateralString = Precise::string_div(Precise::string_mul($leftSide, $contractsAbs), '1', $quotePrecision);
                    }
                } else {
                    // walletBalance = ($contracts * $contractSize) * (±1/entryPrice - (±1 - mmp) / $liquidationPrice)
                    $onePlusMaintenanceMarginPercentageString = null;
                    $entryPriceSignString = $entryPriceString;
                    if ($side === 'short') {
                        $onePlusMaintenanceMarginPercentageString = Precise::string_sub('1', $maintenanceMarginPercentageString);
                    } else {
                        $onePlusMaintenanceMarginPercentageString = Precise::string_sub('-1', $maintenanceMarginPercentageString);
                        $entryPriceSignString = Precise::string_mul('-1', $entryPriceSignString);
                    }
                    $leftSide = Precise::string_mul($contractsAbs, $contractSizeString);
                    $rightSide = Precise::string_sub(Precise::string_div('1', $entryPriceSignString), Precise::string_div($onePlusMaintenanceMarginPercentageString, $liquidationPriceString));
                    $basePrecision = $this->precision_from_string($this->safe_string($precision, 'base'));
                    if ($basePrecision !== null) {
                        $collateralString = Precise::string_div(Precise::string_mul($leftSide, $rightSide), '1', $basePrecision);
                    }
                }
            }
        } else {
            $collateralString = $this->safe_string($position, 'isolatedMargin');
        }
        $collateralString = ($collateralString === null) ? '0' : $collateralString;
        $collateral = $this->parse_number($collateralString);
        $markPrice = $this->parse_number($this->omit_zero($this->safe_string($position, 'markPrice')));
        $timestamp = $this->safe_integer($position, 'updateTime');
        if ($timestamp === 0) {
            $timestamp = null;
        }
        $maintenanceMarginPercentage = $this->parse_number($maintenanceMarginPercentageString);
        $maintenanceMarginString = Precise::string_mul($maintenanceMarginPercentageString, $notionalStringAbs);
        if ($maintenanceMarginString === null) {
            // for a while, this new value was a backup to the existing calculations, but in future we might prioritize this
            $maintenanceMarginString = $this->safe_string($position, 'maintMargin');
        }
        $maintenanceMargin = $this->parse_number($maintenanceMarginString);
        $initialMarginString = null;
        $initialMarginPercentageString = null;
        $leverageString = $this->safe_string($position, 'leverage');
        if ($leverageString !== null) {
            $leverage = intval($leverageString);
            $rational = $this->is_round_number(fmod(1000, $leverage));
            $initialMarginPercentageString = Precise::string_div('1', $leverageString, 8);
            if (!$rational) {
                $initialMarginPercentageString = Precise::string_add($initialMarginPercentageString, '1e-8');
            }
            $unrounded = Precise::string_mul($notionalStringAbs, $initialMarginPercentageString);
            $initialMarginString = Precise::string_div($unrounded, '1', 8);
        } else {
            $initialMarginString = $this->safe_string($position, 'initialMargin');
            $unrounded = Precise::string_mul($initialMarginString, '1');
            $initialMarginPercentageString = Precise::string_div($unrounded, $notionalStringAbs, 8);
        }
        $marginRatio = null;
        $percentage = null;
        if (!Precise::string_equals($collateralString, '0')) {
            $marginRatio = $this->parse_number(Precise::string_div(Precise::string_add(Precise::string_div($maintenanceMarginString, $collateralString), '5e-5'), '1', 4));
            $percentage = $this->parse_number(Precise::string_mul(Precise::string_div($unrealizedPnlString, $initialMarginString, 4), '100'));
        }
        $positionSide = $this->safe_string($position, 'positionSide');
        $hedged = $positionSide !== 'BOTH';
        return $this->safe_position(array(
            'info' => $position,
            'id' => null,
            'symbol' => $symbol,
            'contracts' => $contracts,
            'contractSize' => $contractSize,
            'unrealizedPnl' => $unrealizedPnl,
            'leverage' => $this->parse_number($leverageString),
            'liquidationPrice' => $liquidationPrice,
            'collateral' => $collateral,
            'notional' => $notional,
            'markPrice' => $markPrice,
            'entryPrice' => $entryPrice,
            'timestamp' => $timestamp,
            'initialMargin' => $this->parse_number($initialMarginString),
            'initialMarginPercentage' => $this->parse_number($initialMarginPercentageString),
            'maintenanceMargin' => $maintenanceMargin,
            'maintenanceMarginPercentage' => $maintenanceMarginPercentage,
            'marginRatio' => $marginRatio,
            'datetime' => $this->iso8601($timestamp),
            'marginMode' => $marginMode,
            'side' => $side,
            'hedged' => $hedged,
            'percentage' => $percentage,
            'stopLossPrice' => null,
            'takeProfitPrice' => null,
        ));
    }

    public function fetch_positions_risk(?array $symbols = null, $params = array ()) {
        /**
         * fetch positions risk
         *
         * @see https://asterdex.github.io/aster-api-website/futures-v3/account%26trades/#position-information-v3-user_data
         *
         * @param {string[]|null} $symbols list of unified market $symbols
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return {array} data on the positions risk
         */
        if ($symbols !== null) {
            if ((gettype($symbols) !== 'array' || array_keys($symbols) !== array_keys(array_keys($symbols)))) {
                throw new ArgumentsRequired($this->id . ' fetchPositionsRisk() requires an array argument for symbols');
            }
        }
        $this->load_markets_and_sign_in();
        $this->load_leverage_brackets(false, $params);
        $request = array();
        $response = $this->fapiPrivateGetV3PositionRisk ($this->extend($request, $params));
        //
        //     array(
        //         {
        //             "entryPrice" => "6563.66500",
        //             "marginType" => "isolated",
        //             "isAutoAddMargin" => "false",
        //             "isolatedMargin" => "15517.54150468",
        //             "leverage" => "10",
        //             "liquidationPrice" => "5930.78",
        //             "markPrice" => "6679.50671178",
        //             "maxNotionalValue" => "20000000",
        //             "positionSide" => "LONG",
        //             "positionAmt" => "20.000", // negative value for 'SHORT'
        //             "symbol" => "BTCUSDT",
        //             "unRealizedProfit" => "2316.83423560",
        //             "updateTime" => 1625474304765
        //         }
        //     )
        //
        $result = array();
        for ($i = 0; $i < count($response); $i++) {
            $rawPosition = $response[$i];
            $entryPriceString = $this->safe_string($rawPosition, 'entryPrice');
            if (Precise::string_gt($entryPriceString, '0')) {
                $result[] = $this->parse_position_risk($response[$i]);
            }
        }
        $symbols = $this->market_symbols($symbols);
        return $this->filter_by_array_positions($result, 'symbol', $symbols, false);
    }

    public function fetch_positions(?array $symbols = null, $params = array ()): array {
        /**
         * fetch all open positions
         *
         * @see https://asterdex.github.io/aster-api-website/futures-v3/account%26trades/#position-information-v3-user_data
         *
         * @param {string[]} [$symbols] list of unified market $symbols
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {string} [$params->method] method name to call, "positionRisk", "account" or "option", default is "positionRisk"
         * @return {array[]} a list of ~@link https://docs.ccxt.com/#/?id=position-structure position structure~
         */
        $defaultMethod = null;
        list($defaultMethod, $params) = $this->handle_option_and_params($params, 'fetchPositions', 'method');
        if ($defaultMethod === null) {
            $options = $this->safe_dict($this->options, 'fetchPositions');
            if ($options === null) {
                $defaultMethod = $this->safe_string($this->options, 'fetchPositions', 'positionRisk');
            } else {
                $defaultMethod = 'positionRisk';
            }
        }
        if ($defaultMethod === 'positionRisk') {
            return $this->fetch_positions_risk($symbols, $params);
        } elseif ($defaultMethod === 'account') {
            return $this->fetch_account_positions($symbols, $params);
        } else {
            throw new NotSupported($this->id . '.options["fetchPositions"]["method"] or $params["method"] = "' . $defaultMethod . '" is invalid, please choose between "account" and "positionRisk"');
        }
    }

    public function parse_account_positions($account, $filterClosed = false) {
        $positions = $this->safe_list($account, 'positions');
        $assets = $this->safe_list($account, 'assets', array());
        $balances = array();
        for ($i = 0; $i < count($assets); $i++) {
            $entry = $assets[$i];
            $currencyId = $this->safe_string($entry, 'asset');
            $code = $this->safe_currency_code($currencyId);
            $crossWalletBalance = $this->safe_string($entry, 'crossWalletBalance');
            $crossUnPnl = $this->safe_string($entry, 'crossUnPnl');
            $balances[$code] = array(
                'crossMargin' => Precise::string_add($crossWalletBalance, $crossUnPnl),
                'crossWalletBalance' => $crossWalletBalance,
            );
        }
        $result = array();
        for ($i = 0; $i < count($positions); $i++) {
            $position = $positions[$i];
            $marketId = $this->safe_string($position, 'symbol');
            $market = $this->safe_market($marketId, null, null, 'contract');
            $code = $market['linear'] ? $market['quote'] : $market['base'];
            $maintenanceMargin = $this->safe_string($position, 'maintMargin');
            // check for maintenance margin so empty $positions are not returned
            $isPositionOpen = ($maintenanceMargin !== '0') && ($maintenanceMargin !== '0.00000000');
            if (!$filterClosed || $isPositionOpen) {
                // sometimes not all the codes are correctly returned...
                if (is_array($balances) && array_key_exists($code, $balances)) {
                    $parsed = $this->parse_account_position($this->extend($position, array(
                        'crossMargin' => $balances[$code]['crossMargin'],
                        'crossWalletBalance' => $balances[$code]['crossWalletBalance'],
                    )), $market);
                    $result[] = $parsed;
                }
            }
        }
        return $result;
    }

    public function parse_account_position($position, ?array $market = null) {
        $marketId = $this->safe_string($position, 'symbol');
        $market = $this->safe_market($marketId, $market, null, 'contract');
        $symbol = $this->safe_string($market, 'symbol');
        $leverageString = $this->safe_string($position, 'leverage');
        $leverage = ($leverageString !== null) ? intval($leverageString) : null;
        $initialMarginString = $this->safe_string($position, 'initialMargin');
        $initialMargin = $this->parse_number($initialMarginString);
        $initialMarginPercentageString = null;
        if ($leverageString !== null) {
            $initialMarginPercentageString = Precise::string_div('1', $leverageString, 8);
            $rational = $this->is_round_number(fmod(1000, $leverage));
            if (!$rational) {
                $initialMarginPercentageString = Precise::string_div(Precise::string_add($initialMarginPercentageString, '1e-8'), '1', 8);
            }
        }
        // to notionalValue
        $usdm = (is_array($position) && array_key_exists('notional', $position));
        $maintenanceMarginString = $this->safe_string($position, 'maintMargin');
        $maintenanceMargin = $this->parse_number($maintenanceMarginString);
        $entryPriceString = $this->safe_string($position, 'entryPrice');
        $entryPrice = $this->parse_number($entryPriceString);
        $notionalString = $this->safe_string_2($position, 'notional', 'notionalValue');
        $notionalStringAbs = Precise::string_abs($notionalString);
        $notional = $this->parse_number($notionalStringAbs);
        $contractsString = $this->safe_string($position, 'positionAmt');
        $contractsStringAbs = Precise::string_abs($contractsString);
        if ($contractsString === null) {
            $entryNotional = Precise::string_mul(Precise::string_mul($leverageString, $initialMarginString), $entryPriceString);
            $contractSizeNew = $this->safe_string($market, 'contractSize');
            $contractsString = Precise::string_div($entryNotional, $contractSizeNew);
            $contractsStringAbs = Precise::string_div(Precise::string_add($contractsString, '0.5'), '1', 0);
        }
        $contracts = $this->parse_number($contractsStringAbs);
        $leverageBrackets = $this->safe_dict($this->options, 'leverageBrackets', array());
        $leverageBracket = $this->safe_list($leverageBrackets, $symbol, array());
        $maintenanceMarginPercentageString = null;
        for ($i = 0; $i < count($leverageBracket); $i++) {
            $bracket = $leverageBracket[$i];
            if (Precise::string_lt($notionalStringAbs, $bracket[0])) {
                break;
            }
            $maintenanceMarginPercentageString = $bracket[1];
        }
        $maintenanceMarginPercentage = $this->parse_number($maintenanceMarginPercentageString);
        $unrealizedPnlString = $this->safe_string($position, 'unrealizedProfit');
        $unrealizedPnl = $this->parse_number($unrealizedPnlString);
        $timestamp = $this->safe_integer($position, 'updateTime');
        if ($timestamp === 0) {
            $timestamp = null;
        }
        $isolated = $this->safe_bool($position, 'isolated');
        if ($isolated === null) {
            $isolatedMarginRaw = $this->safe_string($position, 'isolatedMargin');
            $isolated = !Precise::string_eq($isolatedMarginRaw, '0');
        }
        $marginMode = null;
        $collateralString = null;
        $walletBalance = null;
        if ($isolated) {
            $marginMode = 'isolated';
            $walletBalance = $this->safe_string($position, 'isolatedWallet');
            $collateralString = Precise::string_add($walletBalance, $unrealizedPnlString);
        } else {
            $marginMode = 'cross';
            $walletBalance = $this->safe_string($position, 'crossWalletBalance');
            $collateralString = $this->safe_string($position, 'crossMargin');
        }
        $collateral = $this->parse_number($collateralString);
        $marginRatio = null;
        $side = null;
        $percentage = null;
        $liquidationPriceStringRaw = null;
        $liquidationPrice = null;
        $contractSize = $this->safe_value($market, 'contractSize');
        $contractSizeString = $this->number_to_string($contractSize);
        if (Precise::string_equals($notionalString, '0')) {
            $entryPrice = null;
        } else {
            $side = Precise::string_lt($notionalString, '0') ? 'short' : 'long';
            $marginRatio = $this->parse_number(Precise::string_div(Precise::string_add(Precise::string_div($maintenanceMarginString, $collateralString), '5e-5'), '1', 4));
            $percentage = $this->parse_number(Precise::string_mul(Precise::string_div($unrealizedPnlString, $initialMarginString, 4), '100'));
            if ($usdm) {
                // calculate liquidation price
                //
                // $liquidationPrice = ($walletBalance / ($contracts * (±1 . mmp))) . (±$entryPrice / (±1 . mmp))
                //
                // mmp = $maintenanceMarginPercentage
                // where ± is negative for long and positive for short
                // TODO => calculate liquidation price for coinm $contracts
                $onePlusMaintenanceMarginPercentageString = null;
                $entryPriceSignString = $entryPriceString;
                if ($side === 'short') {
                    $onePlusMaintenanceMarginPercentageString = Precise::string_add('1', $maintenanceMarginPercentageString);
                } else {
                    $onePlusMaintenanceMarginPercentageString = Precise::string_add('-1', $maintenanceMarginPercentageString);
                    $entryPriceSignString = Precise::string_mul('-1', $entryPriceSignString);
                }
                $leftSide = Precise::string_div($walletBalance, Precise::string_mul($contractsStringAbs, $onePlusMaintenanceMarginPercentageString));
                $rightSide = Precise::string_div($entryPriceSignString, $onePlusMaintenanceMarginPercentageString);
                $liquidationPriceStringRaw = Precise::string_add($leftSide, $rightSide);
            } else {
                // calculate liquidation price
                //
                // $liquidationPrice = ($contracts * $contractSize(±1 - mmp)) / (±1/entryPrice * $contracts * $contractSize - $walletBalance)
                //
                $onePlusMaintenanceMarginPercentageString = null;
                $entryPriceSignString = $entryPriceString;
                if ($side === 'short') {
                    $onePlusMaintenanceMarginPercentageString = Precise::string_sub('1', $maintenanceMarginPercentageString);
                } else {
                    $onePlusMaintenanceMarginPercentageString = Precise::string_sub('-1', $maintenanceMarginPercentageString);
                    $entryPriceSignString = Precise::string_mul('-1', $entryPriceSignString);
                }
                $size = Precise::string_mul($contractsStringAbs, $contractSizeString);
                $leftSide = Precise::string_mul($size, $onePlusMaintenanceMarginPercentageString);
                $rightSide = Precise::string_sub(Precise::string_mul(Precise::string_div('1', $entryPriceSignString), $size), $walletBalance);
                $liquidationPriceStringRaw = Precise::string_div($leftSide, $rightSide);
            }
            $pricePrecision = $this->precision_from_string($this->safe_string($market['precision'], 'price'));
            $pricePrecisionPlusOne = $pricePrecision + 1;
            $pricePrecisionPlusOneString = (string) $pricePrecisionPlusOne;
            // round half up
            $rounder = new Precise ('5e-' . $pricePrecisionPlusOneString);
            $rounderString = (string) $rounder;
            $liquidationPriceRoundedString = Precise::string_add($rounderString, $liquidationPriceStringRaw);
            $truncatedLiquidationPrice = Precise::string_div($liquidationPriceRoundedString, '1', $pricePrecision);
            if ($truncatedLiquidationPrice[0] === '-') {
                // user cannot be liquidated
                // since he has more $collateral than the $size of the $position
                $truncatedLiquidationPrice = null;
            }
            $liquidationPrice = $this->parse_number($truncatedLiquidationPrice);
        }
        $positionSide = $this->safe_string($position, 'positionSide');
        $hedged = $positionSide !== 'BOTH';
        return array(
            'info' => $position,
            'id' => null,
            'symbol' => $symbol,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'initialMargin' => $initialMargin,
            'initialMarginPercentage' => $this->parse_number($initialMarginPercentageString),
            'maintenanceMargin' => $maintenanceMargin,
            'maintenanceMarginPercentage' => $maintenanceMarginPercentage,
            'entryPrice' => $entryPrice,
            'notional' => $notional,
            'leverage' => $this->parse_number($leverageString),
            'unrealizedPnl' => $unrealizedPnl,
            'contracts' => $contracts,
            'contractSize' => $contractSize,
            'marginRatio' => $marginRatio,
            'liquidationPrice' => $liquidationPrice,
            'markPrice' => null,
            'collateral' => $collateral,
            'marginMode' => $marginMode,
            'side' => $side,
            'hedged' => $hedged,
            'percentage' => $percentage,
        );
    }

    public function fetch_account_positions(?array $symbols = null, $params = array ()) {
        /**
         * @ignore
         * fetch account positions
         https://asterdex.github.io/aster-api-website/futures-v3/account%26trades/#position-information-v3-user_data
         * @param {string[]} [$symbols] list of unified market $symbols
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return {array} data on account positions
         */
        if ($symbols !== null) {
            if ((gettype($symbols) !== 'array' || array_keys($symbols) !== array_keys(array_keys($symbols)))) {
                throw new ArgumentsRequired($this->id . ' fetchPositions() requires an array argument for symbols');
            }
        }
        $this->load_markets_and_sign_in();
        $this->load_leverage_brackets(false, $params);
        $response = $this->fapiPrivateGetV4Account ($params);
        $filterClosed = null;
        list($filterClosed, $params) = $this->handle_option_and_params($params, 'fetchAccountPositions', 'filterClosed', false);
        $result = $this->parse_account_positions($response, $filterClosed);
        $symbols = $this->market_symbols($symbols);
        return $this->filter_by_array_positions($result, 'symbol', $symbols, false);
    }

    public function load_leverage_brackets($reload = false, $params = array ()) {
        $this->load_markets_and_sign_in();
        // by default cache the leverage $bracket
        // it contains useful stuff like the maintenance margin and initial margin for positions
        $leverageBrackets = $this->safe_dict($this->options, 'leverageBrackets');
        if (($leverageBrackets === null) || ($reload)) {
            $response = $this->fapiPrivateGetV3LeverageBracket ($params);
            //
            //    [
            //        {
            //            "symbol" => "TRUTHUSDT",
            //            "brackets" => [
            //                array(
            //                    "bracket" => "1",
            //                    "initialLeverage" => "50",
            //                    "notionalCap" => "5000",
            //                    "notionalFloor" => "0",
            //                    "maintMarginRatio" => "0.01",
            //                    "cum" => "0.0"
            //                ),
            //                array(
            //                    "bracket" => "2",
            //                    "initialLeverage" => "20",
            //                    "notionalCap" => "10000",
            //                    "notionalFloor" => "5000",
            //                    "maintMarginRatio" => "0.025",
            //                    "cum" => "75.0"
            //                ),
            //                ...
            //
            $this->options['leverageBrackets'] = $this->create_safe_dictionary();
            for ($i = 0; $i < count($response); $i++) {
                $entry = $response[$i];
                $marketId = $this->safe_string($entry, 'symbol');
                $symbol = $this->safe_symbol($marketId, null, null, 'contract');
                $brackets = $this->safe_list($entry, 'brackets', array());
                $result = array();
                for ($j = 0; $j < count($brackets); $j++) {
                    $bracket = $brackets[$j];
                    $floorValue = $this->safe_string($bracket, 'notionalFloor');
                    $maintenanceMarginPercentage = $this->safe_string($bracket, 'maintMarginRatio');
                    $result[] = array( $floorValue, $maintenanceMarginPercentage );
                }
                $this->options['leverageBrackets'][$symbol] = $result;
            }
        }
        return $this->options['leverageBrackets'];
    }

    public function keccak_message($message) {
        return '0x' . $this->hash($message, 'keccak', 'hex');
    }

    public function sign_message($message, $privateKey) {
        return $this->sign_hash($this->keccak_message($message), mb_substr($privateKey, -64));
    }

    public function sign_withdraw_payload($withdrawPayload, $network): string {
        $chainId = $this->safe_integer($withdrawPayload, 'chainId');
        $domain = array(
            'chainId' => $chainId,
            'name' => 'Aster',
            'verifyingContract' => $this->safe_string($this->options, 'zeroAddress'),
            'version' => '1',
        );
        $messageTypes = array(
            'Action' => array(
                array( 'name' => 'type', 'type' => 'string' ),
                array( 'name' => 'destination', 'type' => 'address' ),
                array( 'name' => 'destination Chain', 'type' => 'string' ),
                array( 'name' => 'token', 'type' => 'string' ),
                array( 'name' => 'amount', 'type' => 'string' ),
                array( 'name' => 'fee', 'type' => 'string' ),
                array( 'name' => 'nonce', 'type' => 'uint256' ),
                array( 'name' => 'aster chain', 'type' => 'string' ),
            ),
        );
        $request = array(
            'type' => 'Withdraw',
            'destination' => $this->safe_string($withdrawPayload, 'receiver'),
            'destination Chain' => $network,
            'token' => $this->safe_string($withdrawPayload, 'asset'),
            'amount' => $this->safe_string($withdrawPayload, 'amount'),
            'fee' => $this->safe_string($withdrawPayload, 'fee'),
            'nonce' => $this->safe_integer($withdrawPayload, 'userNonce'),
            'aster chain' => 'Mainnet',
        );
        $msg = $this->eth_encode_structured_data($domain, $messageTypes, $request);
        $signature = $this->sign_message($msg, $this->privateKey);
        return $signature;
    }

    public function withdraw(string $code, float $amount, string $address, ?string $tag = null, $params = array ()): array {
        /**
         * make a withdrawal
         *
         * @see https://asterdex.github.io/aster-api-website/spot-v3/account%26trades/#withdraw-user_data
         * @see https://asterdex.github.io/aster-api-website/futures-v3/deposit%26withdrawal/#withdraw-by-fapiv3-evm-futures
         * @see https://asterdex.github.io/aster-api-website/futures-v3/deposit%26withdrawal/#withdraw-by-fapiv3-evm-spot
         *
         * @param {string} $code unified $currency $code
         * @param {float} $amount the $amount to withdraw
         * @param {string} $address the $address to withdraw to
         * @param {string} $tag
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return {array} a ~@link https://docs.ccxt.com/#/?id=transaction-structure transaction structure~
         */
        list($tag, $params) = $this->handle_withdraw_tag_and_params($tag, $params);
        $this->check_address($address);
        $this->load_markets_and_sign_in();
        $currency = $this->currency($code);
        $nonce = $this->milliseconds() * 1000;
        $request = array(
            'asset' => $currency['id'],
            'receiver' => $address,
            'userNonce' => (string) $nonce,
        );
        $chainId = $this->safe_integer($params, 'chainId');
        // TODO => check how ARBI signature would work
        $networks = $this->safe_dict($this->options, 'networks', array());
        $network = $this->safe_string_upper($params, 'network');
        $network = $this->safe_string($networks, $network, $network);
        if (($chainId === null) && ($network !== null)) {
            $chainIds = $this->safe_dict($this->options, 'networksToChainId', array());
            $chainId = $this->safe_integer($chainIds, $network);
        }
        if ($chainId === null) {
            throw new ArgumentsRequired($this->id . ' withdraw require $chainId or $network parameter');
        }
        $request['chainId'] = $chainId;
        $fee = $this->safe_string($params, 'fee');
        if ($fee === null) {
            throw new ArgumentsRequired($this->id . ' withdraw require $fee parameter');
        }
        $request['fee'] = $fee;
        $params = $this->omit($params, array( 'chainId', 'network', 'fee' ));
        $request['amount'] = $this->currency_to_precision($code, $amount, $network);
        $request['userSignature'] = $this->sign_withdraw_payload($request, $network);
        $response = $this->sapiPrivatePostV3AsterUserWithdraw ($this->extend($request, $params));
        //
        //   {
        //       "withdrawId" => "1097219372504338432",
        //       "hash" => "0x9e6baa3eb75d92a1164eef51a0cc97b9591930518ba3e8e5ab40ce524ba4e463"
        //   }
        //
        return $this->parse_transaction($response, $currency);
    }

    public function parse_transaction($transaction, ?array $currency = null): array {
        return array(
            'info' => $transaction,
            'id' => $this->safe_string($transaction, 'withdrawId'),
            'txid' => $this->safe_string($transaction, 'hash'),
            'timestamp' => null,
            'datetime' => null,
            'network' => null,
            'address' => null,
            'addressTo' => null,
            'addressFrom' => null,
            'tag' => null,
            'tagTo' => null,
            'tagFrom' => null,
            'type' => 'withdrawal',
            'amount' => null,
            'currency' => null,
            'status' => null,
            'updated' => null,
            'internal' => null,
            'comment' => null,
            'fee' => null,
        );
    }

    public function transfer(string $code, float $amount, string $fromAccount, string $toAccount, $params = array ()): array {
        /**
         * transfer $currency internally between wallets on the same account
         *
         * @see https://asterdex.github.io/aster-api-website/spot-v3/account%26trades/#perp-spot-transfer-trade
         * @see https://asterdex.github.io/aster-api-website/futures-v3/account%26trades/#transfer-between-futures-and-spot-transfer
         *
         * @param {string} $code unified $currency $code
         * @param {float} $amount amount to transfer
         * @param {string} $fromAccount account to transfer from
         * @param {string} $toAccount account to transfer to
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return {array} a ~@link https://docs.ccxt.com/#/?id=transfer-structure transfer structure~
         */
        $this->load_markets_and_sign_in();
        $currency = $this->currency($code);
        $request = array(
            'asset' => $currency['id'],
            'amount' => $this->currency_to_precision($code, $amount),
        );
        $type = null;
        $fromId = null;
        if ($fromAccount !== null) {
            $fromId = strtoupper($this->convert_type_to_account($fromAccount));
        }
        $toId = null;
        if ($toAccount !== null) {
            $toId = strtoupper($this->convert_type_to_account($toAccount));
        }
        if ($fromId === 'SPOT' && $toId === 'FUTURE') {
            $type = 'SPOT_FUTURE';
        } elseif ($fromId === 'FUTURE' && $toId === 'SPOT') {
            $type = 'FUTURE_SPOT';
        }
        if ($type === null) {
            throw new ArgumentsRequired($this->id . ' transfer() requires $fromAccount and $toAccount parameters to be either SPOT or FUTURE');
        }
        $response = null;
        $defaultClientTranId = $this->number_to_string($this->milliseconds());
        $clientTranId = $this->safe_string($params, 'clientTranId', $defaultClientTranId);
        $request['kindType'] = $type;
        $request['clientTranId'] = $clientTranId;
        $response = $this->sapiPrivatePostV3AssetWalletTransfer ($this->extend($request, $params));
        return $this->parse_transfer($response, $currency);
    }

    public function parse_transfer(array $transfer, ?array $currency = null): array {
        $currencyId = $this->safe_string($transfer, 'code');
        return array(
            'info' => $transfer,
            'id' => $this->safe_string($transfer, 'tranId'),
            'timestamp' => null,
            'datetime' => null,
            'currency' => $this->safe_currency_code($currencyId, $currency),
            'amount' => null,
            'fromAccount' => null,
            'toAccount' => null,
            'status' => $this->parse_transfer_status($this->safe_string($transfer, 'status')),
        );
    }

    public function parse_transfer_status(?string $status): ?string {
        $statuses = array(
            'SUCCESS' => 'ok',
        );
        return $this->safe_string($statuses, $status, $status);
    }

    public function hash_message($binaryMessage) {
        // $binaryMessage = $this->encode(message);
        $binaryMessageLength = $this->binary_length($binaryMessage);
        $x19 = $this->base16_to_binary('19');
        $newline = $this->base16_to_binary('0a');
        $prefix = $this->binary_concat($x19, $this->encode('Ethereum Signed Message:'), $newline, $this->encode($this->number_to_string($binaryMessageLength)));
        return '0x' . $this->hash($this->binary_concat($prefix, $binaryMessage), 'keccak', 'hex');
    }

    public function sign_hash($hash, $privateKey) {
        $this->check_required_credentials();
        $signature = $this->ecdsa(mb_substr($hash, -64), mb_substr($privateKey, -64), 'secp256k1', null);
        $r = $signature['r'];
        $s = $signature['s'];
        $v = $this->int_to_base16($this->sum(27, $signature['v']));
        return '0x' . str_pad($r, 64, '0', STR_PAD_LEFT) . str_pad($s, 64, '0', STR_PAD_LEFT) . $v;
    }

    public function sign($path, $api = 'public', $method = 'GET', $params = array (), $headers = null, $body = null) {
        $url = $this->implode_hostname($this->urls['api'][$api]) . '/' . $path;
        if ($api === 'fapiPublic' || $api === 'sapiPublic') {
            if ($params) {
                $url .= '?' . $this->rawencode($params);
            }
        } elseif ($api === 'fapiPrivate' || $api === 'sapiPrivate') {
            $this->check_required_credentials();
            $nonce = $this->milliseconds() * 1000;
            // Sign using EIP-712 typed data per the AsterSignTransaction spec
            $zeroAddress = $this->safe_string($this->options, 'zeroAddress', '0x0000000000000000000000000000000000000000');
            $v3ChainId = $this->safe_integer($this->options, 'v3ChainId', 1666);
            $signerAddress = $this->safe_string($this->options, 'signerAddress');
            if ($signerAddress === null) {
                throw new ArgumentsRequired($this->id . ' requires $signerAddress in options when use v3 api');
            }
            $domain = array(
                'name' => 'AsterSignTransaction',
                'version' => '1',
                'chainId' => $v3ChainId,
                'verifyingContract' => $zeroAddress,
            );
            $messageTypes = array(
                'Message' => array(
                    array( 'name' => 'msg', 'type' => 'string' ),
                ),
            );
            // Build v3 $params => original endpoint $params . $nonce (macroseconds) . user . signer
            // Note => timestamp and recvWindow are not used for v3; $nonce replaces timestamp
            $finalParams = $this->extend(array(
                'nonce' => (string) $nonce,
                'user' => $this->walletAddress,
                'signer' => $signerAddress,
            ), $params);
            $paramString = null;
            $paramsToEncode = null;
            $isApproveBuilder = (mb_strpos($path, '/approveBuilder') !== false);
            if ($isApproveBuilder) {
                // $domain['name'] = 'Aster';
                $messageTypes = array(
                    'ApproveBuilder' => array(
                        array( 'name' => 'Builder', 'type' => 'string' ),
                        array( 'name' => 'MaxFeeRate', 'type' => 'string' ),
                        array( 'name' => 'BuilderName', 'type' => 'string' ),
                        array( 'name' => 'AsterChain', 'type' => 'string' ),
                        array( 'name' => 'User', 'type' => 'string' ),
                        array( 'name' => 'Nonce', 'type' => 'uint256' ),
                    ),
                );
                unset($finalParams['signer']); // signer is not needed for approveBuilder endpoint
                $paramString = $this->encode_values_with_json($finalParams);
                $paramsToEncode = $this->capitalize_keys($finalParams);
            } else {
                $paramString = $this->encode_values_with_json($finalParams);
                $paramsToEncode = array( 'msg' => $paramString );
            }
            $encodedMessage = $this->eth_encode_structured_data($domain, $messageTypes, $paramsToEncode);
            $signature = $this->sign_message($encodedMessage, $this->privateKey);
            $queryString = $paramString . '&' . 'signature=' . $signature;
            if ($method === 'GET') {
                $url .= '?' . $queryString;
            } else {
                $headers = array();
                $headers['Content-Type'] = 'application/x-www-form-urlencoded';
                $body = $queryString;
            }
        }
        return array( 'url' => $url, 'method' => $method, 'body' => $body, 'headers' => $headers );
    }

    public function encode_values_with_json(array $values): string {
        $encodedString = '';
        $keys = is_array($values) ? array_keys($values) : array();
        for ($i = 0; $i < count($keys); $i++) {
            $key = $keys[$i];
            $value = $values[$key];
            $isObj = (gettype($value) === 'array' && array_keys($value) === array_keys(array_keys($value))) || $this->is_dictionary($value);
            $valueJsonified = $isObj ? $this->json($value) : (string) $value;
            $encoded = $this->encode_uri_component($valueJsonified);
            $encodedString .= $key . '=' . $encoded . '&';
        }
        return mb_substr($encodedString, 0, -1 - 0);
    }

    public function capitalize_keys(array $dict): array {
        $capitalized = array();
        $keys = is_array($dict) ? array_keys($dict) : array();
        for ($i = 0; $i < count($keys); $i++) {
            $key = $keys[$i];
            $value = $dict[$key];
            $capitalizedKey = $this->capitalize($key);
            $capitalized[$capitalizedKey] = $value;
        }
        return $capitalized;
    }

    public function load_markets_and_sign_in() {
        array( $this->load_markets(), $this->sign_in() );
    }

    public function sign_in($params = array ()) {
        /**
         * sign in, must be called prior to using other authenticated methods
         *
         * @see https://asterdex.github.io/aster-api-website/asterCode/integration-flow/
         *
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return response from exchange
         */
        if ($this->is_empty_string($this->privateKey)) {
            if (!$this->is_empty_string($this->apiKey) || !$this->is_empty_string($this->secret)) {
                throw new NotSupported($this->id . 'after the latest upgrade (v4.5.52), CCXT now expects the l1 private key to be provided in the credentials.');
            }
            return false;
        }
        if (strlen($this->privateKey) > 66) {
            throw new NotSupported($this->id . ' after the latest update (v4.5.52), CCXT now expects the l1 private key to be provided in the credentials.');
        }
        $this->initialize_client($params);
        return true;
    }

    public function initialize_client($params = array ()) {
        $builderFee = $this->safe_bool($params, 'builderFee', $this->safe_bool($this->options, 'builderFee', true)); // we shouldn't omit here
        if (!$builderFee) {
            return false; // skip if builder fee is not enabled
        }
        $approvedBuilderFee = $this->safe_bool($this->options, 'approvedBuilderFee', false);
        if ($approvedBuilderFee) {
            return true; // skip if builder fee is already approved
        }
        $result = $this->fapiPrivateGetV3Builder ();
        //
        //    array(
        //        {
        //            "userAddress" => "0x35a5B33Be664B09F78b5089eb6185f71c8a7f11f",
        //            "builderAddress" => "0x1F5877C19e3777Cfd15F9d57253eA4aA5254Ec39",
        //            "maxFeeRate" => "0.001",
        //            "builderName" => "ccxt"
        //        }
        //    )
        //
        $approvedBuilders = $result;
        $length = count($approvedBuilders);
        $found = false;
        for ($i = 0; $i < $length; $i++) {
            $builderInfo = $this->safe_dict($approvedBuilders, $i, array());
            $builderAccountId = $this->safe_string($builderInfo, 'builderAddress');
            if ($builderAccountId === $this->safe_string($this->options, 'builder')) {
                $found = true;
                break;
            }
        }
        if (!$found) {
            $this->options['approvedBuilderFee'] = true;
            try {
                $request = array(
                    'builder' => $this->safe_string($this->options, 'builder'),
                    'builderName' => $this->safe_string($this->options, 'builderName', 'ccxt'),
                    'maxFeeRate' => $this->safe_string($this->options, 'builderRate'),
                    'signatureChainId' => $this->safe_integer($this->options, 'v3ChainId', 1666),
                    'asterChain' => 'Mainnet',
                );
                $authResponse = $this->fapiPrivatePostV3ApproveBuilder ($this->extend($request, $params));
                //
                // array("code" => 200,"msg" => "success")
                //
                $codeRes = $this->safe_integer($authResponse, 'code');
                if ($codeRes !== 200) {
                    throw new ExchangeError('Builder authorization failed, ' . $this->json($authResponse));
                }
            } catch (Exception $e) {
                $this->options['approvedBuilderFee'] = false;
                $this->options['builderFee'] = false; // disable if err
            }
        }
        return null; // just c#
    }

    public function handle_errors(int $httpCode, string $reason, string $url, string $method, array $headers, string $body, $response, $requestHeaders, $requestBody) {
        if ($response === null) {
            return null; // fallback to default error handler
        }
        //
        //    {
        //        "code" => -1121,
        //        "msg" => "Invalid symbol.",
        //    }
        //
        $code = $this->safe_string($response, 'code');
        $message = $this->safe_string($response, 'msg');
        if ($code !== null && $code !== '200') {
            $feedback = $this->id . ' ' . $body;
            $this->throw_exactly_matched_exception($this->exceptions['exact'], $message, $feedback);
            $this->throw_exactly_matched_exception($this->exceptions['exact'], $code, $feedback);
            $this->throw_broadly_matched_exception($this->exceptions['broad'], $message, $feedback);
            throw new ExchangeError($feedback); // unknown $message
        }
        return null;
    }
}
